import{_ as t,a as e}from"./chunks/查询额度成功.wz9SQqrH.js";import{_ as n,o as d,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Menambahkan pCloud Channel","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/upload/pcloud.md","filePath":"id-ID/upload/pcloud.md","lastUpdated":1781962217000}'),o={name:"id-ID/upload/pcloud.md"};function s(r,a,p,u,c,h){return d(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="menambahkan-pcloud-channel" tabindex="-1">Menambahkan pCloud Channel <a class="header-anchor" href="#menambahkan-pcloud-channel" aria-label="Permalink to &quot;Menambahkan pCloud Channel&quot;">​</a></h1><h2 id="paling-cocok-untuk" tabindex="-1">Paling Cocok Untuk <a class="header-anchor" href="#paling-cocok-untuk" aria-label="Permalink to &quot;Paling Cocok Untuk&quot;">​</a></h2><ul><li>Anda memiliki pCloud account dan ingin ImgBed menyimpan images di pCloud.</li><li>Anda nyaman memakai pCloud account email dan password sebagai channel credentials.</li></ul><h2 id="yang-perlu-disiapkan-dahulu" tabindex="-1">Yang Perlu Disiapkan Dahulu <a class="header-anchor" href="#yang-perlu-disiapkan-dahulu" aria-label="Permalink to &quot;Yang Perlu Disiapkan Dahulu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Mengapa Dibutuhkan</th></tr></thead><tbody><tr><td>pCloud account email</td><td>Digunakan untuk sign in ke pCloud API</td></tr><tr><td>pCloud password</td><td>Digunakan untuk sign in ke pCloud API</td></tr><tr><td>API host</td><td>Default <code>api.pcloud.com</code>. EU accounts bisa memakai <code>eapi.pcloud.com</code>.</td></tr><tr><td>Storage directory</td><td>Tempat files disimpan. Default adalah <code>imgbed</code>.</td></tr></tbody></table><h2 id="di-mana-menambahkannya" tabindex="-1">Di Mana Menambahkannya <a class="header-anchor" href="#di-mana-menambahkannya" aria-label="Permalink to &quot;Di Mana Menambahkannya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Buka Upload Settings.</li><li>Klik <code>Add Channel</code> di kanan atas.</li><li>Pilih <code>pCloud</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Mengidentifikasi pCloud channel ini, misalnya <code>Personal pCloud</code></td><td>Yes</td></tr><tr><td>Account email</td><td>Email login pCloud Anda</td><td>Yes</td></tr><tr><td>Password</td><td>Password pCloud Anda</td><td>Yes</td></tr><tr><td>API host</td><td>pCloud API host. Default <code>api.pcloud.com</code>.</td><td>No</td></tr><tr><td>Storage directory</td><td>Directory untuk menyimpan files. Default <code>imgbed</code>.</td><td>No</td></tr></tbody></table><p>Pilih API host berdasarkan account region:</p><table tabindex="0"><thead><tr><th>Account Region</th><th>API Host</th></tr></thead><tbody><tr><td>Default / US</td><td><code>api.pcloud.com</code></td></tr><tr><td>Europe</td><td><code>eapi.pcloud.com</code></td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><ol><li>Buka Upload Settings.</li><li>Klik <code>Add Channel</code>.</li><li>Pilih <code>pCloud</code>.</li><li>Masukkan channel name yang mudah dikenali.</li><li>Masukkan pCloud account email.</li><li>Masukkan pCloud password.</li><li>Biarkan API host sebagai <code>api.pcloud.com</code>, atau pakai <code>eapi.pcloud.com</code> untuk EU accounts.</li><li>Biarkan storage directory sebagai <code>imgbed</code>, atau ubah ke folder pilihan Anda.</li><li>Save channel.</li></ol><p><img src="'+t+'" alt="Configure channel" loading="lazy"></p><h2 id="cara-memeriksa" tabindex="-1">Cara Memeriksa <a class="header-anchor" href="#cara-memeriksa" aria-label="Permalink to &quot;Cara Memeriksa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>pCloud channel card muncul setelah save.</td></tr><tr><td>Channel switch</td><td>Switch di card tetap enabled.</td></tr><tr><td>Email display</td><td>Card menampilkan connected pCloud email.</td></tr><tr><td>Quota query</td><td>Setelah query berhasil, used dan total capacity ditampilkan.</td></tr><tr><td>Upload test</td><td>Test image muncul di configured pCloud storage directory.</td></tr></tbody></table><p><img src="'+e+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="mengapa-bukan-oauth2" tabindex="-1">Mengapa Bukan OAuth2? <a class="header-anchor" href="#mengapa-bukan-oauth2" aria-label="Permalink to &quot;Mengapa Bukan OAuth2?&quot;">​</a></h3><p>pCloud OAuth2 tidak self-service secara default. Anda perlu email pCloud dan meminta mereka mengaktifkannya.</p><p>Flow pCloud OAuth2 saat ini juga tidak mendukung short-lived upload link workflow yang dibutuhkan ImgBed, jadi channel ini memakai login account email dan password.</p><h3 id="api-host-mana-yang-harus-dipakai" tabindex="-1">API Host Mana yang Harus Dipakai? <a class="header-anchor" href="#api-host-mana-yang-harus-dipakai" aria-label="Permalink to &quot;API Host Mana yang Harus Dipakai?&quot;">​</a></h3><p>Default:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.pcloud.com</span></span></code></pre></div><p>Untuk EU accounts:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eapi.pcloud.com</span></span></code></pre></div><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Siapkan pCloud email dan password</span></span>
<span class="line"><span>-&gt; Buka Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Pilih pCloud</span></span>
<span class="line"><span>-&gt; Isi channel name / email / password</span></span>
<span class="line"><span>-&gt; Biarkan API host sebagai api.pcloud.com kecuali account Anda di Europe</span></span>
<span class="line"><span>-&gt; Biarkan storage directory sebagai imgbed kecuali perlu folder lain</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Query quota</span></span>
<span class="line"><span>-&gt; Upload test image</span></span></code></pre></div>`,28)])])}const b=n(o,[["render",s]]);export{g as __pageData,b as default};
